use bench_fixture::is_valid_ipv4;

#[test]
fn accepts_valid_addresses() {
    assert!(is_valid_ipv4("192.168.1.1"));
    assert!(is_valid_ipv4("0.0.0.0"));
    assert!(is_valid_ipv4("255.255.255.255"));
    assert!(is_valid_ipv4("10.0.0.1"));
}

#[test]
fn rejects_too_many_octets() {
    assert!(!is_valid_ipv4("1.2.3.4.5"));
}

#[test]
fn rejects_few_octets() {
    assert!(!is_valid_ipv4("1.2.3"));
    assert!(!is_valid_ipv4("1"));
}

#[test]
fn rejects_out_of_range() {
    assert!(!is_valid_ipv4("256.1.1.1"));
    assert!(!is_valid_ipv4("1.256.1.1"));
    assert!(!is_valid_ipv4("1.1.1.256"));
}

#[test]
fn rejects_non_numeric() {
    assert!(!is_valid_ipv4("a.b.c.d"));
    assert!(!is_valid_ipv4("1.2.3.a"));
}

#[test]
fn rejects_leading_zeros() {
    assert!(!is_valid_ipv4("01.1.1.1"));
    assert!(!is_valid_ipv4("1.001.1.1"));
}

#[test]
fn rejects_empty_and_garbage() {
    assert!(!is_valid_ipv4(""));
    assert!(!is_valid_ipv4("..."));
    assert!(!is_valid_ipv4("1.2.3."));
    assert!(!is_valid_ipv4(".1.2.3"));
}

